@spec library_spec  src=tests/specs/library_spec.lua  loc=164  sha=be5d40d  cases=11
@exercises configManager (h.cm)
@surface   cm:getAt, cm:set, cm:defaultFor
@harness   mk

# Intent
  Pin-tests for library.lua: the shared project/library/factory tier module.
  Instantiated directly over a harness cm (phase 1 has no production caller).
  One case per verb: names, get, localize, forkToProject, publish, revert,
  modified, tidy, delete -- plus the synthetic floor's exemptions.

# Helpers
  @fn mkLib(h)  @ 9-14

# Cases
  @case 'names splits the three tiers and drops the synthetic floor'  [harness]  @ 18-30
  @case 'get resolves project over library over factory'  [harness]  @ 33-44
  @case 'localize copies a factory entry to project and is idempotent'  [harness]  @ 47-58
  @case 'localize skips synthetic names'  [harness]  @ 61-67
  @case 'forkToProject localizes then returns the project copy'  [harness]  @ 70-77
  @case 'publish copies the project entry to the library tier'  [harness]  @ 80-88
  @case 'publish no-ops without a project copy'  [harness]  @ 91-97
  @case 'revert overwrites the project copy from its source'  [harness]  @ 100-109
  @case 'modified: false pristine, true divergent, false for a source-less entry'  [harness]  @ 112-126
  @case 'tidy drops pristine unreferenced entries, keeps inUse and divergent ones'  [harness]  @ 129-146
  @case 'delete removes from the named tier and refuses synthetic names'  [harness]  @ 149-162

# Uses (outbound edges)
  @use call cm:getAt  @ 51,53,56,66,76,87,96,107,141,157,159,161
  @use call cm:set  @ 54,120,133
  @use call cm:defaultFor  @ 107,134,135

